package main

import "fmt"

func main() {
    capitals := map[string]string{
        "US": "Washington",
        "UK": "London",
        "JP": "Tokyo",
    }

    // Add
    capitals["IN"] = "New Delhi"

    // Get with check
    if capital, ok := capitals["JP"]; ok {
        fmt.Println("Capital of JP:", capital)
    }

    // Delete
    delete(capitals, "UK")

    // Iterate
    for country, capital := range capitals {
        fmt.Printf("%s -> %s\n", country, capital)
    }
}
